INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098939d","title":"Американский вампир. Книга 1","author":"Скотт Снайдер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003054605/140/ddfd/Skott_Snajder__Amerikanskij_vampir._Kniga_1.jpg","isbn":"978-5-389-14002-8","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Хитрый, безжалостный, опасный, как гремучая змея, Скиннер Свит известен своим строптивым нравом. Но он, первый кто стал вампиром на американской земле,  и он не таков, как другие ночные твари. Он сильнее, яростнее и черпает энергию от солнца. Свит — первый в новой генерации кровососов, истинно американский вампир.  Лос-Анджелес двадцатых годов, куда молодые и красивые слетаются, как мотыльки, на опаляющие огни Голливуда… Но тут действует кое-что пострашнее обычной человеческой алчности, и начинающей актрисе Перл Джонс предстоит убедиться в этом на собственной шкуре. Когда ее мечты о карьере кинозвезды оборачиваются кровавым кошмаром, Свит дает ей единственный шанс остаться в живых и отомстить.  Лас-Вегас, середина тридцатых. Дни шика и безумной роскоши еще впереди, однако азартные игры, проституция и насильственные преступления — главные виды экономической деятельности, благодаря которым город уже заслужил себе прозвище «Город греха». Кэш Маккоган, суровый шеф полиции Лас-Вегаса, намерен его очистить — даже если придется пойти против консорциума богачей. Но толстосумы – не единственные, кто желает запустить зубы в этот золотоносный участок.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-08","rating":4.5,"review":"","added":9999261,"hdCover":""},{"id":"098939c","title":"Скотт Пилигрим против Вселенной. Том 5. Злое издание","author":"Брайан Ли О''Мэлли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002168452/140/6a3e/Brajan_Li_O039Melli__Skott_Piligrim_protiv_Vselennoj._Tom_5._Zloe_izdanie.jpg","isbn":"978-5-91339-481-1","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Скотт Пилигрим отметил двадцать четвертый день рождения, но следующего может и не быть. Ему пора сразиться с двумя злыми бывшими Рамоны - да, с двумя сразу - и они натравили на Скотта роботов! Неважно, портят ли они вечеринку Джули или срывают первый концерт Sex Bob-omb за несколько месяцев, Скотту надо с ними разобраться. Но получится ли у него победить злых роботов и не испортить отношения с Рамоной? Успеет ли он победить её злых бывших до того, как Рамона - О БОЖЕ - его бросит? Ответы на эти вопросы Скотт найдёт внутри книги... если выживет!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-08","rating":3.5,"review":"","added":9999260,"hdCover":""},{"id":"098939b","title":"Гамбит. Омнибус. Рожденный вором. Надгробный блюз. Король воров","author":"Джеймс Асмус,Кирк,Невес,Баррионуэво","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002985894/140/08d5/__Gambit._Omnibus._Rozhdennyj_vorom._Nadgrobnyj_blyuz._Korol_vorov.jpg","isbn":"978-5-04-098854-9","publisher":"Fanzon","pubDate":"2018","language":"","series":"Комиксы. Кино","genres":["Зарубежная фантастика"],"annotation":"17 выпусков о главном воре-мутанте вселенной Marvel! Многообещающие локации (от затерянного храма в джунглях Гватемалы до Нью-Йорка!). Легендарный персонаж (умение играть в карты и очарование южанина, каджунский шарм и редкая смекалка!). Также в сюжете — Пит Виздом из МИ-13 и соблазнительная воровка Джоэль, неубиваемый криминальный босс Надгробие и участница «Поразительных Мстителей» Шельма. Подарочное издание в твердом переплете.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-08","rating":3.5,"review":"","added":9999259,"hdCover":""},{"id":"098939a","title":"Веном. Дьявольская свора","author":"Каллен Банн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002995911/140/e25a/Kallen_Bann__Venom._Dyavolskaya_svora.jpg","isbn":"978-5-91878-319-1","publisher":"Фантастика Книжный Клуб","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"ДЬЯВОЛ ВНУТРИ! Мстители поручают недавно принятому в их ряды Агенту Веному схватить Дэймона Хеллстрома — но, чтобы арестовать Cына Сатаны, Флэшу придётся одолеть Злобных чудовищ! Что же это за демонические твари из Преисподней и как они связаны с Веномом? Последствия сделки Флэша Томпсона с дьяволом достигнут апогея, и на свободу вырвется адский Веном! Затем Флэш и Кэти Кирнан отправятся в Филадельфию, чтобы расследовать череду исчезновений, а симбиот вместе с ними заглянет в город братской любви и наведёт там порядок — в своём неповторимом стиле. Проигрывая в битве с Неопознанными, Томпсон выпустит на волю своих внутренних демонов, но как низко он падёт, если утратит контроль? И сумеет ли Флэш сдержать живущую в нём тьму, пока та не поставила Филадельфию на колени? Издание содержит выпуски «Веном» № 23–25, 28–30, написанные Калленом Банном («Росомаха») и нарисованные Тони Сайласом («Удивительный Человек-Паук. Концы света»).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-08","rating":3,"review":"","added":9999258,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989399","title":"Y: Последний мужчина. Книга 5","author":"Брайан К. Вон,Пиа Гуэрра,Хосе Марсан-мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002888140/140/d4b2/__Y_Poslednij_muzhchina._Kniga_5.jpg","isbn":"978-5-389-15023-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"В 2002 году мир навсегда изменился. Повсюду на земле все мужчины и мальчики, все млекопитающие с Y-хромосомой разом упали и умерли. Из-за гибели более чем половины человечества шестеренки общества застопорились. Теперь перед женщинами стоит задача: собрать мир по частям и уберечь цивилизацию от полного коллапса.  \"Гендерцид\", впрочем, оказался не вполне тотальным. По неведомым причинам молодой человек Йорик Браун и его ручной капуцин Амперсанд остались живы. За одну ночь безвестный юнец оказался главным человеком на планете — возможным ключом к загадке гендерноспецифической эпидемии.  А самый важный для самого Йорика человек находится за 7 000 миль от него, и юноша готов на все, чтобы ее отыскать. Однако их разделяет целый океан, и надежда на встречу все слабее — новые угрозы подступают со всех сторон.  Впервые собранный в издании делюкс графический роман VERTIGO сценариста Брайана К. Вона и художницы Пии Гуэрры \"Y — Последний мужчина\" в ярких красках рисует ответ на давний вопрос: что на самом деле произошло бы с последним мужчиной на Земле?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-07","rating":5,"review":"","added":9999257,"hdCover":""},{"id":"0989398","title":"Y: Последний мужчина. Книга 4","author":"Брайан К. Вон,Пиа Гуэрра,Хосе Марсан-мл.,Goran Sudzuka","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002824633/140/f6f7/__Y_Poslednij_muzhchina._Kniga_4.jpg","isbn":"978-5-389-14437-8","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"В 2002 году мир навсегда изменился. Повсюду на земле все мужчины и мальчики, все млекопитающие с Y-хромосомой разом упали и умерли. Из-за гибели более чем половины человечества шестеренки общества застопорились. Теперь перед женщинами стоит задача: собрать мир по частям и уберечь цивилизацию от полного коллапса.  «Гендерцид», впрочем, оказался не вполне тотальным. По неведомым причинам молодой человек Йорик Браун и его ручной капуцин Амперсанд остались живы. За одну ночь безвестный юнец оказался главным человеком на планете — возможным ключом к загадке гендерноспецифической эпидемии.  А самый важный для самого Йорика человек по-прежнему для него недостижим. Но теперь, три года спустя, с великими трудами преодолев 10 000 миль, последний мужчина приближается к тому, чтобы узнать правду о своей невесте – и поразительные факты о причинах своего спасения.  Впервые собранный в издании делюкс графический роман VERTIGO сценариста Брайана К. Вона и художницы Пии Гуэрры «Y: Последний мужчина» в ярких красках рисует ответ на давний вопрос: что на самом деле произошло бы с последним мужчиной на Земле?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-07","rating":4.5,"review":"","added":9999256,"hdCover":""},{"id":"0989397","title":"Y: Последний мужчина. Книга 3","author":"Брайан К. Вон,Хосе Марсан-мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002622459/140/5789/__Y_Poslednij_muzhchina._Kniga_3.jpg","isbn":"978-5-389-13088-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"В 2002 году мир навсегда изменился. Повсюду на земле все мужчины и мальчики, все млекопитающие с Y-хромосомой разом упали и умерли. Из-за гибели более чем половины человечества шестеренки общества застопорились. Теперь перед женщинами стоит задача: собрать мир по частям и уберечь цивилизацию от полного коллапса.  «Гендерцид», впрочем, оказался не вполне тотальным. По неведомым причинам молодой человек Йорик Браун и его ручной капуцин Амперсанд остались живы. За одну ночь безвестный юнец оказался главным человеком на планете — возможным ключом к загадке гендерноспецифической эпидемии.  А самый важный для самого Йорика человек находится за 7 000 миль от него, и юноша готов на все, чтобы ее отыскать. Однако их разделяет целый океан, и надежда на встречу все слабее — новые угрозы подступают со всех сторон.  Впервые собранный в издании делюкс графический роман VERTIGO сценариста Брайана К. Вона и художницы Пии Гуэрры «Y — Последний мужчина» в ярких красках рисует ответ на давний вопрос: что на самом деле произошло бы с последним мужчиной на Земле?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-07","rating":4.5,"review":"","added":9999255,"hdCover":""},{"id":"0989396","title":"Y: Последний мужчина. Книга 2","author":"Брайан К. Вон,Пиа Гуэрра,Хосе Марсан-мл.,Горан Парлов","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002275797/140/1471/__Y_Poslednij_muzhchina._Kniga_2.jpg","isbn":"978-5-389-12021-1","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"В 2002 году мир навсегда изменился. Повсюду на земле все мужчины и мальчики, все млекопитающие с Y-хромосомой разом упали и умерли. Из-за гибели более чем половины человечества шестеренки общества застопорились. Теперь перед женщинами стоит задача: собрать мир по частям и уберечь цивилизацию от полного коллапса.  «Гендерцид», впрочем, оказался не вполне тотальным. По неведомым причинам молодой человек Йорик Браун и его ручной капуцин Амперсанд остались живы. За одну ночь безвестный юнец оказался главным человеком на планете — возможным ключом к загадке гендерноспецифической эпидемии.  А самый важный для самого Йорика человек находится за 10 000 миль от него, и юноша готов на все, чтобы ее отыскать. Однако пускаясь в путь по миру, где остались одни женщины, парнишка и обезьянка обнаруживают, что за ними охотятся — с самыми разными целями.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-07","rating":4.5,"review":"","added":9999254,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989395","title":"Y: Последний мужчина. Книга 1","author":"Брайан К. Вон,Пиа Гуэрра,Хосе Марсан-мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002006705/140/c698/__Y_Poslednij_muzhchina._Kniga_1.jpg","isbn":"978-5-389-11783-9","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Что бы вы сделали, окажись вы последним мужчиной на Земле? Йорик Браун, двадцати двухлетний безработный и фокусник-любитель, не ждал, что когда-нибудь ему придется всерьез отвечать на этот вопрос. Но когда все другие мужчины умерли (а с ними и все самцы млекопитающих на планете), Йорик и его ручная обезьянка Амперсанд внезапно обнаружили, что от них зависит судьба человечества.  Так начинается удивительное путешествие: два последних носителя Y-хромосомы пытаются раскрыть загадку эпидемии, уничтожившей других мужчин, и сохранить будущее человечества. Но как одному человеку спасти целый вид, если его сердце принадлежит единственной женщине — а она на другой стороне земного шара?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-07","rating":4.5,"review":"","added":9999253,"hdCover":""},{"id":"0989394","title":"Боун. Том 7. Покойные поля","author":"Джефф Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002999312/140/cd4b/Dzheff_Smit__Boun._Tom_7._Pokojnye_polya.jpg","isbn":"9785950067020","publisher":"Рамона","pubDate":"2019","language":"Русский","series":"Боун/ Bone","genres":["Комиксы","манга","графические романы"],"annotation":"Древний вулкан извергается, пепел застилает солнце и покрывает землю. Повелитель Саранчи освобождён! На этом апокалиптичном фоне братья Боун вместе с Торн и бабушкой Бен пытаются добраться до безопасности в Атейе. Тем временем Луций тяжело ранен и загнан вместе с жителями деревни в пещере Старика.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-07","rating":4.5,"review":"","added":9999252,"hdCover":""},{"id":"0989393","title":"Удивительный Человек-Паук. Снова в черном","author":"Джей Майкл Стражински","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002912081/140/ca83/Dzhej_Majkl_Strazhinski__Udivitelnyj_ChelovekPauk._Snova_v_chernom.jpg","isbn":"978-5-04-099066-5","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Чёрное сердце. Чёрная душа. Человек-Паук снова в чёрном.  Гражданская война закончилась: одна сторона победила, другая проиграла, и все правила изменились. Теперь, когда весь мир узнал личность Человека-Паука, тот стал мишенью для нападения давних врагов. Жизнь Питера Паркера перевернулась вверх дном… равно как и жизнь членов его семьи.  И в этом кошмаре, разросшемся как паутина, из которой не вырваться, Человек-Паук принимает тьму и понимает, что должен сделать шаг… последний шаг… в борьбе против своих сильнейших врагов, среди которых Песочный Человек, таинственный Другой и смертоносный Кингпин.  В сборник вошли комиксы \"Удивительный Человек-Паук\" #539-543, \"Дружелюбный сосед Человек-Паук\" #17-23 и Ежегодник #1.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-07","rating":3,"review":"","added":9999251,"hdCover":""},{"id":"0989392","title":"Люди Икс. Худший из Людей Икс","author":"Макс Бемис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003008707/140/f665/Maks_Bemis__Lyudi_Iks._Hudshij_iz_Lyudej_Iks.jpg","isbn":"978-5-04-102862-6","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Это история изгоя среди изгоев, который всего лишь пытается влиться: Бэйли Хоскинс вдруг обнаружил, что он мутант. Для того, кто никогда не был особенным и никогда не выделялся, это стало важным событием. И вот он входит в коридоры школы Ксавье для одарённых подростков. Чего ему ждать и каков его дар? Бэйли уже давно привык быть нелюбимым, но стоит ли его бояться? Он пытается найти своё место среди других учеников, но Икс-вселенная большая... Возможно, Мистик разглядит его потенциал? Или, может, у Магнето появится для него задание? Или же магия путешествия во времени покажет нам его будущие триумфы и славу? (На это особо не надейтесь.) Итог: Бэйли Хоскинс? Худший. Из. Людей Икс.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-07","rating":3.5,"review":"","added":9999250,"hdCover":""},{"id":"0989391","title":"Росомаха. Старик Логан","author":"Марк Миллар,Стив МакНивен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001420416/140/93c2/__Rosomaha._Starik_Logan.jpg","isbn":"978-5-91339-329-6","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Когда-то Марк Миллар («Мордобой»/«Особо опасен») уже делал историю про Росомаху - «Враг государства», но на этот раз он превзошёл самого себя. В этом ему помог его бессменный \"брат по оружию\" в «Гражданской Войне» - художник Стив Макнивен.  Смешав супергероику далёкой антиутопии мира «Людей Икс: Дней минувшего будущего» с диким постапокалиптическим миром «Безумного Макса» и трагическим путешествием героя, напоминающего архетипы Клинта Иствуда, Марк Миллар создал комикс о Росомахе, который находится на распутье и не знает, кто он теперь и кем он хочет бить. Безумные экшн-сцены Миллара и динамичная раскадровка Макнивена заставят вас с нетерпением перелистывать страницы, пока Росомаха не прикончит последнего злодея в своём бесконечном поиске мирного существования.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-07","rating":4.5,"review":"","added":9999249,"hdCover":""},{"id":"0989390","title":"Ultimate Comics Avengers: Next Generation","author":"Марк Миллар,Карлос Пачеко","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002954608/140/3e5a/__Ultimate_Comics_Avengers_Next_Generation.jpg","isbn":"9780785140108","publisher":"Marvel","pubDate":"2010","language":"Английский","series":"Ultimate Comics Avengers","genres":["Комиксы","манга","графические романы"],"annotation":"It''s a mind-blowing, heart-pounding, and gut-wrenching event of epic proportions! When a highly-classified secret threatens Captain America, only the newly-returned Nick Fury has the tools to bring ''em in!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-06","rating":4,"review":"","added":9999248,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098938f","title":"Звёздные Войны. Дарт Вейдер. Полное издание (сборник)","author":"Кирон Гиллен,Джейсон Аарон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002997733/140/c662/__Zvjozdnye_Vojny._Dart_Vejder._Polnoe_izdanie_sbornik.jpg","isbn":"978-5-04-099846-3","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Звездные войны. Дарт Вейдер (тв)","genres":["Комиксы","манга","графические романы"],"annotation":"После уничтожения \"Звезды Смерти\" Восстание обрело новую надежду. Если Империя намерена нанести ответный удар, безжалостный повелитель ситхов Дарт Вейдер обязан вновь подчинить себе Галактику - и вернуть расположение учителя! А Император уже подыскивает ему замену, поэтому Вейдер должен проявить себя. Однако этому мешают его личные дела: выяснив имя юного джедая, переломившего ход битвы при Явине, Вейдер приступает к судьбоносным поискам Люка Скайуокера! Предпринимая шаги по обоим направлениям, повелитель ситхов призывает себе на помощь таких классических негодяев, как Боба Фетт и Джабба Хатт, а также новых персонажей: доктора Афру и дроидов-убийц Три Нуля и БиТи. Но неподвластные ситху события грозят расстроить все его планы. Смогут ли повстанцы сразить его… или же это удастся его конкурентам? А может, никто не в силах прервать его имперский марш? Один из величайших фантастических злодеев играет главную роль в этом чествовании тёмной стороны \"Звёздных войн\"!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-06","rating":4.5,"review":"","added":9999247,"hdCover":""},{"id":"098938e","title":"Сорвиголова Фрэнка Миллера и Клауса Янсона. Том 1","author":"Фрэнк Миллер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002815000/140/858d/Frenk_Miller__Sorvigolova_Frenka_Millera_i_Klausa_Yansona._Tom_1.jpg","isbn":"978-5-91339-603-7","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Сорвиголова появился во вселенной Marvel в 1964 году, но важнейшим этапом его существования всё же стал ран сценариста/художника Фрэнка Миллера и художника/контуровщика Клауса Янсона. С 1979 по 1983 год Миллер буквально создал персонажа заново, при этом быстро став крупной и влиятельной фигурой в мире комиксов.  Миллер видоизменил таких важных персонажей мира Сорвиголовы, как репортёр Бен Урих, роковая красотка Чёрная Вдова, безумный киллер Меченый, вооружённый пилами Гладиатор и могучий преступный босс Кингпин.  Также Миллер представил читателям загадочного наставника Сорвиголовы Стика, смертоносных ниндзя из клана Руки, а также бывшую возлюбленную Мэтта Электру - прекрасную наёмницу, ставшую одной из самых запоминающихся героинь Marvel. Смешав традиционную супергероику с историями о боевых искусствах, обречённой любви и личных трагедиях, Миллер создал комиксы, определившие сущность Сорвиголовы. Первый том собрания этих комиксов вы и держите в руках!.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-05","rating":4,"review":"","added":9999246,"hdCover":""},{"id":"098938d","title":"Вселенная DC. Rebirth. Бэтмен. Detective Comics. Книга 3. Лига Теней","author":"Джеймс Тайнион IV","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002964543/140/10d9/Dzhejms_Tajnion_IV__Vselennaya_DC._Rebirth._Betmen._Detective_Comics._Kniga_3._L.jpg","isbn":"978-5-389-15773-6","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Они никогда не нападали открыто и не брали на себя ответственность за свои действия, поэтому Бэтмен был убежден, что Лига Теней – не что иное, как миф для глупцов, которому нет подтверждения. Очередной способ воздействия на фанатиков-убийц. Но Лига Теней во главе с Леди Шивой пришла в Готэм, и соратники Темного Рыцаря один за другим попали в расставленные ею сети. Перед силами зла склонились и ангел смерти Азраил, и Бэтвинг, чья броня оснащена по последнему слову техники, бывший злодей Глиноликий и даже опытный боец Бэтвумен. Сможет ли Темный Рыцарь заключить сделку со своим заклятым врагом, чтобы спасти команду и очистить город от наемников? Или Готэм навсегда останется в тени? «Бэтмен. Detective Comics. Книга 3. Лига Теней» – еще одна захватывающая глава истории о Темном Рыцаре и его отважной команде, вышедшая из-под пера писателя Джеймса Тайниона IV и проиллюстрированная художниками Марсио Такарой («Флэш) и Кристианом Дусэ («Бэтмен и Робин навсегда»). Сборник включает выпуски «Detective Comics» #950–956.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-05","rating":3,"review":"","added":9999245,"hdCover":""},{"id":"098938c","title":"Вселенная DC. Rebirth. Бэтмен. Detective Comics. Книга 2. Синдикат Жертв (сборник)","author":"Джеймс Тайнион IV","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002869953/140/8c0d/Dzhejms_Tajnion_IV__Vselennaya_DC._Rebirth._Betmen._Detective_Comics._Kniga_2._S.jpg","isbn":"978-5-389-15041-6","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Уничтожить Темного Рыцаря – и спасти Готэм. В городе появился Синдикат Жертв, таинственная организация, чьи цели непонятны. Ясно лишь одно: они настроены очень серьезно. Все, что они хотят, – заявить о себе и остановить войну. Используя свои пугающие сверхспособности, они стремятся уничтожить всех плащеносцев, начиная с Бэтмена. Пусть в окружении Темного Рыцаря достаточно героев – Бэтвумен, Сирота, Спойлер, Глиноликий и Бэтвинг, – однако Красный Робин, который был душой и сердцем команды, погиб. Его смерть легла на всех остальных тяжким бременем. Сыграет ли это на руку Синдикату Жертв? И как очередная война отразится на жителях Готэма? Возможно, Бэтмену и впрямь стоит распустить команду и повесить свой плащ на гвоздь. Писатель Джеймс Тайнион IV («Бэтмен навсегда») и художники Альваро Мартинес («Бэтмен и Робин навсегда») и Эдди Барроуз («Найтвинг») продолжают одобренное критиками обновление Темного Рыцаря и его союзников! Бонусом для читателей станет история из двух выпусков, нарисованная Беном Оливером («The Multiversity»), в которой Бэтмен действует на территории карантинной зоны Монстртауна. Эти два выпуска являются своего рода прологом серии «Бэтвумен. Rebirth». Сборник включает выпуски «Detective Comics» #943–949.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-05","rating":4,"review":"","added":9999244,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
