  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098938b","title":"Вселенная DC. Rebirth. Бэтмен. Книга 4. Война Шуток и Загадок (сборник)","author":"Дэнни Мики,Клей Манн,Том Кинг,Seth Mann,Джун Чанг,Джон Ливси,‎ Mikel Janin,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002964545/140/1510/__Vselennaya_DC._Rebirth._Betmen._Kniga_4._Vojna_Shutok_i_Zagadok_sbornik.jpg","isbn":"978-5-389-16049-1","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Выстоит ли Готэм в войне между Джокером и Загадочником?  Джокер и Загадочник – потенциальные союзники, но только на первый взгляд. На заре становления Темного Рыцаря каждый из них решил для себя, что он и только он должен уничтожить Бэтмена... Теперь и тот, и другой скорее сожгут Готэм дотла, чем позволят одержать сопернику верх в Войне Шуток и Загадок. В противостоянии двух преступных гениев каждый злодей в Готэме был поставлен перед выбором: на чью сторону встать – психопата Джокера или обезумевшего Загадочника? Множественные невинные жертвы, вооруженные нападения и разбои – долго же жителям города придется зализывать раны. Даже Бэтмену пришлось прибегнуть к крайним мерам, чтобы помешать кровопролитию. Сумеет ли он остановить войну и не предать свои идеалы?  Любимая критиками звездная команда писателя Тома Кинга («Грэйсон», «Вижн») и художника Микеля Ханина («Темная лига справедливости») представляет вашему вниманию одну из самых мрачных глав саги о Темном Рыцаре – «Бэтмен. Книга 4. Война шуток и загадок». В сборник вошли выпуски #25–32, а также невероятная душераздирающая история появления Кайтмена. О да, мать вашу!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-05","rating":4,"review":"","added":9999243,"hdCover":""},{"id":"098938a","title":"Вселенная DC. Rebirth. Бэтмен. Книга 3. Я - Бэйн (сборник)","author":"Дэвид Финч,Том Кинг","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002908547/140/b0da/__Vselennaya_DC._Rebirth._Betmen._Kniga_3._Ya__Bejn_sbornik.jpg","isbn":"978-5-389-15027-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Возмездие Бэйна.  Бэйн и Бэтмен. Отважный герой и бесстрашный злодей. Лишь одному из них суждено уцелеть в этой схватке. Бэтмен вторгся на территорию Бэйна, лишил его покоя и сломал ему спину. И Бэйн отправился в Готэм-сити с единственной целью: покончить с Бэтменом раз и навсегда и забрать того, кто заставит боль отступить. Но сначала Бэйн уничтожит всех, кого Темный Рыцарь когда-либо любил: юных борцов с преступностью, комиссара Гордона, Женщину-Кошку и Альфреда. Он собирается сокрушить даже психов, содержащихся в стенах лечебницы Аркхем. Как подняться на ноги, если ты уже пропустил несколько ударов? Как собраться с силами и выиграть войну? Бэйн – настоящий кошмар, и он постоянно напоминает об этом. Но на каждого Бэйна есть свой Бэтмен.  Книга «Бэтмен. Книга 3. Я – Бэйн» от суперзвездного художника Дэвида Финча («Чудо-женщина») и не менее популярного сценариста Тома Кинга («Шериф Вавилона») стала очередной захватывающей главой в саге о Темном Рыцаре. В книгу вошли выпуски #16–20, #23–24 «Бэтмена», а также «Бэтмен. Ежегодник» #1.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-05","rating":3.5,"review":"","added":9999242,"hdCover":""},{"id":"0989389","title":"Современный Человек-Паук. Том 1","author":"Брайан Майкл Бендис,Марк Багли,Стюарт Иммонен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002927866/140/ac66/__Sovremennyj_ChelovekPauk._Tom_1.jpg","isbn":"978-5-6041145-3-7","publisher":"Зодиак","pubDate":"2018","language":"Русский","series":"Современный Человек-Паук","genres":["Комиксы","манга","графические романы"],"annotation":"Ещё до смерти Питера Паркера юный Майлз готовится начать новую главу в своей жизни в новой школе. Вот только укус паука дарует подростку невероятные паучьи способности. Теперь Майлз оказывается в непонятном ему мире, вооружённый лишь инстинктами и ответственностью. Сможет ли он сохранить наследие Человека-паука? Пока Майлз пытается привыкнуть к новой роли, его Дядя Аарон, он же Мародёр, узнает его тайну! У него есть свои планы на племянника, вот только он не догадывается, что у него на хвосте сам Скорпион!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-05","rating":4.5,"review":"","added":9999241,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989388","title":"Звездные Войны. Кэнан (сборник)","author":"Грег Вайсман,Greg Weisman,Pepe Larraz","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002867461/140/97f8/__Zvezdnye_Vojny._Kenan_sbornik.jpg","isbn":"978-5-04-097098-8","publisher":"Эксмо, Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Кэнан Джаррус известен как дерзкий, острый на язык лидер разношёрстной команды корабля \"Призрак\", сражающейся за свободу против всемогущей Галактической Империи! Но до того как он взял себе имя Кэнан — до падения Республики, — его звали Кейлеб Дьюм, он был джедаем-падаваном мастера Депы Биллабы. Пришла пора узнать, как этот юнец превратился в отступника, каким мы его знаем теперь! Как Кейлеб избежал чистки, когда канцлер Палпатин отдал Приказ 66, предписывающий убить всех джедаев? Как ему удалось выжить, когда погибла его наставница? И что же делать юному падавану, если его навыки — всё равно что нарисованная на спине мишень? А после отправляйтесь ещё дальше в его прошлое и присоединяйтесь к его первому приключению! В разгар Войн клонов Храм джедаев подвергается нападению, и Кейлеб должен встать на пути у смертельно опасной угрозы. В это же время Депа Биллаба встречается лицом к лицу со своим личным врагом — генералом Гривусом! А спустя годы команде \"Повстанцев\" придётся столкнуться с призраками из прошлого Кэнана уже в настоящем!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-05","rating":4.5,"review":"","added":9999240,"hdCover":""}]');

