  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989387","title":"Вселенная DC. Rebirth. Флэш. Книга 1. Молния бьет дважды","author":"Джошуа Уильямсон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002809288/140/19a1/Dzhoshua_Uilyamson__Vselennaya_DC._Rebirth._Flesh._Kniga_1._Molniya_bet_dvazhdy.jpg","isbn":"978-5-389-14587-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"История начинается со встречи Барри Аллена и Уолли Уэста, которая упоминается в комиксе «Вселенная DC. Rebirth». Воспоминания о забытой Барри Алленом жизни возвращаются к нему, и Алый Спидстер узнает, что в ход времени вмешалась загадочная сила… Разобраться бы с этим, но порожденная Силой Скорости буря проносится через Централ-сити и наделяет способностями мирных жителей. Теперь на героя взвалилась ответственность за воспитание новых спидстеров. Займут ли новички сторону добра или решат использовать дар в корыстных целях?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-05","rating":4,"review":"","added":9999239,"hdCover":""},{"id":"0989386","title":"Человек-Паук. Другой","author":"Питер Дэвид,Джей Майкл Стражински,Реджинальд Хадлин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002845352/140/ec96/__ChelovekPauk._Drugoj.jpg","isbn":"978-5-04-097326-2","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Человек-Паук. Избранное","genres":["Комиксы","манга","графические романы"],"annotation":"Его беспокоят странные сны. Его тревожит растущее чувство опасности. Он убеждён, что все вокруг жаждут его крови. Паучок сталкивается с величайшей угрозой… вероломным врагом, которого в одиночку не одолеть. Но Паук не одинок, с ним его друзья: Рид Ричардс, Стефан Стрэндж и Хэнк Пим. Но смогут ли даже величайшие умы изменить судьбу? И если смогут — пойдут ли на это? Наконец приняв правду, Питер Паркер решает отложить красно-синее трико и провести время с тётей Мэй и Эм Джей. Но у Морлана иные планы… и в этот раз рядом нет Иезекииля, способного помочь стенолазу. Усаживайтесь поудобнее, преданные фанаты, — такой битвы вы ещё не видели, ведь Пауку противостоит враг, которого он ещё никогда не побеждал! Избитый до полусмерти, он оказывается в месте, совершенно не похожем на рай или ад. Человека-Паука ждёт приключение, равного которому у него ещё не было. И если Питер надеется хоть как-то остановить Морлана, у него есть всего два варианта: измениться или умереть!..","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-05","rating":3.5,"review":"","added":9999238,"hdCover":""},{"id":"0989385","title":"Флэшпойнт","author":"Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002724585/140/e95c/Dzheff_Dzhons__Fleshpojnt.jpg","isbn":"978-5-389-13896-4","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Барри Аллен был супергероем. В облике Флэша он сражался со злом. Но в один прекрасный день он не узнал мир вокруг себя. Здесь Чудо-Женщина и Аквамен уже погубили миллионы людей в войне за власть. Здесь Зеленым Фонарем никогда не становился землянин, и ни одна живая душа ничего не слышала о Супермене. Здесь Бэтмен использует кровавые методы в борьбе с противниками, а самый быстрый человек на планете – всего лишь обычный криминалист.  В этом мире у Барри Аллена нет друзей и сверхскорости, но он помнит о том, что было раньше. Осталось всего ничего – убедить других супергероев помочь ему повернуть время вспять...  МИР НИКОГДА НЕ БУДЕТ ПРЕЖНИМ.  Звездная команда в лице писателя Джеффа Джонса («ЛИГА СПРАВЕДЛИВОСТИ») и художника Энди Кьюберта («БЭТМЕН») с гордостью представляют «ФЛЭШПОЙНТ» – незабываемое событие, которое навсегда изменит Вселенную DC!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-05","rating":3.5,"review":"","added":9999237,"hdCover":""},{"id":"0989384","title":"Клаус","author":"Грант Моррисон,Дэн Мора","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002907043/140/c2ff/__Klaus.jpg","isbn":"978-5-04-098212-7","publisher":"Эксмо, Fanzon","pubDate":"2018","language":"Русский","series":"Комиксы. Современная классика","genres":["Комиксы","манга","графические романы","Зарубежное фэнтези"],"annotation":"Его любят дети и взрослые по всему миру… Но знает ли кто-нибудь, откуда на самом деле взялся Санта-Клаус?  Погрузившись в мрачную старину, где сплелись мифы и магия, «Клаус» рассказывает историю о прошлом Санты. О том, как один человек со своим верным волком бросил вызов тоталитарному государству и стоящему за ним древнему злу...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-04","rating":4.5,"review":"","added":9999236,"hdCover":""},{"id":"0989383","title":"Чёрная Вдова. Полное издание","author":"Крис Сэмни,Марк Уэйд,Мэтт Уилсон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002824728/140/a25e/__Chjornaya_Vdova._Polnoe_izdanie.jpg","isbn":"978-5-04-096583-0","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Они поразили вас \"Сорвиголовой\", а теперь команда, получившая премию Айснера, Марк Уэйд и Крис Сэмни, возводит Чёрную Вдову на новый уровень, заставив её пуститься в бега! У Наташи на всю жизнь хватит секретов, а когда самые страшные из них становятся достоянием общественности, о безопасности можно забыть. З.А.Щ.И.Т.А. выступает против своего некогда самого ценного агента, и Наташа начинает в одиночку искать ответы в этой истории, полной захватывающего, кладущего на лопатки экшна и шпионажа! Вдова окажется там, куда предпочла бы никогда не возвращаться, увидит реинкарнацию жуткой Красной Комнаты: Тёмную Комнату! Всё заходит слишком далеко, и Наташе придётся показать, чего она стоит и на что способна.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-04","rating":3.5,"review":"","added":9999235,"hdCover":""},{"id":"0989382","title":"Чудеса","author":"Курт Бьюсик, Алекс Росс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002718658/140/1c0b/Kurt_Byusik_Aleks_Ross__Chudesa.jpg","isbn":"978-5-9909878-7-6","publisher":"Jellyfish Jam","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Взгляните на рождение вселенной Marvel глазами обычного человека. Фотограф Фил Шелдон не обладает какими-то удивительными способностями, но у него есть невероятное журналистское чутье и умение оказаться в нужное время в нужном месте. Вместе с ним, читатель станет свидетелем появления первого Человека-Факела и нападения Нэмора на Нью-Йорк, рождения Мстителей и анти-мутантской паники, вторжения Галактуса и судьбоносной дуэли Человека-Паука с Зеленым Гоблином за жизнь Гвен Стейси.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2019-04","rating":3.5,"review":"","added":9999234,"hdCover":""}]');
